                            {dashboardData.admin.recentAlerts.map((alert, index) => (
                                <div key={index} className={`flex items-start space-x-4 p-4 rounded-xl border ${
                                    alert.type === 'warning' ? 'bg-yellow-25 border-yellow-200' : 'bg-blue-25 border-blue-200'
